sql:
SELECT DISTINCT n.latitude, n.longitude, l.coverage_area
FROM nodes n
JOIN location_areas l ON n.latitude = l.latitude AND n.longitude = l.longitude;

SELECT AVG(connection_time) AS typical_duration
FROM connection_metrics
WHERE signal_strength < 50;

SELECT *
FROM location_areas
WHERE radius = (SELECT MAX(radius) FROM location_areas);

SELECT MAX(num_accesses) AS max_accesses
FROM (
  SELECT COUNT(*) AS num_accesses
  FROM access_logs
  GROUP BY user_id
);

SELECT lac_name, lac_id
FROM location_areas
WHERE latitude > 37.7;

SELECT DISTINCT r.report_type 
FROM reports r
WHERE r.report_data LIKE '%cell_id: 1%';

external_knowledge:
- "beacons" refers to 'node_name';
- "glowing brightly" means the node is 'Active';
- "whispers of trouble" refers to 'alarms' or issues;
- "sounds of health" refers to 'reports' or health status indicators;
- The counts of "whispers of trouble" and "sounds of health" represent the total alarms and total reports, respectively.

- "Lighthouse" metaphorically represents a network node;
- "Beacon" symbolizes the unique identifier for each node;
- "Sending light across the sea" metaphorically describes data usage by the node;
- "Warning bell" symbolizes an alarm event indicating potential issues.
